command.text:
declare @ma_nkt_s varchar(32) select @ma_nkt_s = replace(replace(@ma_nkt, '[', '0'),']', '0')
if exists(select * from @@table where ((replace(replace(ma_nkt, '[', '0'),']', '0') like rtrim(@ma_nkt_s) + '%') or rtrim(@ma_nkt_s) like rtrim(replace(replace(ma_nkt, '[', '0'),']', '0')) + '%')) begin select 'ma_nkt' as field, replace(@$exists, '%s', rtrim(@ma_nkt)) as message return end select @m_trung_so = case when @$cb_yn = 1 then -@$trung_so else @$trung_so end, @datetime0 = getdate(), @datetime2 = getdate(), @user_id0 = @@userID, @user_id2 = @@userID
&Check;

        /* <flatten type="Javascript"> */
var f = this, c = 'v20dmctnkt', id = f.get_id(), g = f.getItem(c)._controlBehavior, v = f._language == 'v', o1 = f.getItem('so_ct1'), o2 = f.getItem('so_ct2'), v1 = o1.value.match(/\d+/g), v2 = o2.value.match(/\d+/g);
var e = (v ? 'Có tồn tại mã chứng từ trùng nhau trong phần thông tin chi tiết, không thể lưu được.' : 'Invalid voucher code, it already exists.');
if (f._checked) {
  var l = g._getColumnOrder('ma_ct'), a = query$Select(g, 'count$1 $groupBy ma_ct');
  for (var i = 0; i < a.length; i++) {
    if (a[i][1] > 1) {
      g._errorObject = g._getItem(i + 1, l);
      f._checked = false;
      $func.hideWait(id);
      $message.show(e, String.format('$find(\'{0}\').focus(\'{1}\');$find(\'{2}\')._errorObject.focus();', id, c, g.get_id()));
      break;
    }
  }
}
if (f._checked) g.setSequenceNumber('line_nbr');

if (f._checked) checkType(f, 'ma_nkt, ten_nkt, so_ct1, so_ct2', f.getItemValue('type'));

if (!v1 || !v2) {
  f._checked = false;
  $func.hideWait(f.get_id());
  $message.show(String.format($df.getResources(f._language, 'Message.RequiredField'), v1 ? o2.field.Label : o1.field.Label), String.format('$find(\'{0}\').getItem(\'so_ct{1}\').focus()', f.get_id(), v1 ? '2' : '1'));
}
/* </flatten> */

script.text:
      &ScriptQueryData;
      &OutlineEntry;

function active$Form&Controller;(f) {
  f.add_onResponseComplete(on$Form&Controller;$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onTabChanged&Controller;);
  f._tabContainer._loaded = true;
  init$Form&Controller;(f);
}
function close$Form&Controller;(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onTabChanged&Controller;);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Form&Controller;$ResponseComplete)} catch (ex) {}
}
function init$Form&Controller;(f) {if (f._action == 'New') {f.setItemValues('ma_dvcs, ten_dvcs', [f._unitCode, f._unitName]);}}
function on$Form&Controller;$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_nkt');
      break;
    default:
      break;
  }
}
function onTabChanged&Controller;(sender, e) {
  var f = sender.parentForm;
  f.focusWhenTabChanged(['ma_dvcs', ['v20dmctnkt', 'ma_ct']]);
}
function onChange&Controller;NumberStart(o) {
  var f = o.parentForm;
  var s = f.getItemValue('so_ct1');
  try {f.setItemValue('so_ct0', formatVoucherNumber(s, 0));} catch (ex) {}
  try {f.setItemValue('so_ct2', formatVoucherNumber(s, 1));} catch (ex) {}
  f.live(f.getItem('so_ct2'));
}
function on&Controller;TypeSelectedIndexChanged(o) {
  var f = o.parentForm;
  f.getItem('cb_yn').disabled = (f.getItemValue('trung_so') == 0);
}
function onChange$Type$&Controller;(f){
  var t = f.getItemValue('type');
  f.getItem('ntype%l').value = ((f._language == 'v') ? (t == 1 ? 'Theo tháng' : 'Theo năm') : (t == 1 ? 'By month' : 'By year');
}
/* <flatten type="Javascript"> */
function formatVoucherNumber(s, type) {
  if (s.length = 0) return '';
  var a = s.match(/\d+/g);
  if (!a) return '';
  if (a.length == 0) return '';

  var l = a[0].length, e = 0;
  for (var i = 1; i < a.length; i++) {
    if (a[i].length > l) {
      l = a[i].length;
      e = i;
    }
  }
  if (l == 0) return '';
  var r, d = a[e];

  if (type == 0) {
    var min = parseInt(d, 10);
    if (min == 0) return '';
    r = String(min - 1);
    l = d.length - r.length;
    for (var i = 0; i < l; i++) {
      r = '0' + r;
    }
  }
  else {
    r = '';
    for (var i = 0; i < l; i++) {
      r += '9';
    }
  }
  r = s.replace(d, r);
  return r;
}
/* </flatten> */
function setObject$Form&Controller;(f, b) {
  var o = f.getItem('ma_dvcs');
  o.field.AllowNulls = !b;
  if (b) {
    var grandNode = o.parentNode.parentNode;
    Sys.UI.DomElement.addCssClass(grandNode, 'Required');
    Sys.UI.DomElement.addCssClass(grandNode, f._id);
  }
}
/* <flatten type="Javascript"> */
function checkType(f, c, u){
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var e = null, name = $func.trim(a[i]), o = f.getItem(name), c = o.value, l = o.field.Label;
    if (c.length > 0) {
      if (u == 1 && c.toUpperCase().indexOf('[MM]') < 0) return showError(f, l, name);
      if (c.toUpperCase().indexOf('[YY]') < 0 && c.toUpperCase().indexOf('[YYYY]') < 0) return showError(f, l, name);
    }
  }
  return true;
}
/* </flatten> */
      &ScriptIrregular;
